31	/// Fact-name prefixes reserved for the diff-mode translation (observed in the
32	/// "Reserved prefixes" check, diff mode only).
33	const RESERVED_PREFIXES: &[&str] = &["DiffIntr", "DiffProto"];
34	
35	/// Word-fill width used by the oracle's pretty-printer for the wrapped
36	/// "Reserved prefixes" header (measured empirically: a line breaks before the
37	/// next word once it would exceed column 69).
38	const FILL_WIDTH: usize = 69;
39	
40	/// Reserved fact names (used as protocol facts -> "Reserved names").
41	const RESERVED_FACTS: &[&str] = &["K", "KU", "KD"];
42	/// Special I/O facts handled by the special-fact / Fr checks.
43	const SPECIAL_FACTS: &[&str] = &["In", "Out", "Fr"];
44	
45	fn is_reserved(name: &str) -> bool {
46	    RESERVED_FACTS.contains(&name)
47	}
48	fn is_special(name: &str) -> bool {
49	    SPECIAL_FACTS.contains(&name)
50	}
51	
52	/// Builtin-fact normalization: fact names matching KU/KD/In/Out/Fr
53	/// case-insensitively (and the exact single letter `K`) denote the builtin
54	/// facts; `Ku(x)` reports as `!KU( x )` and `FR(x)` as `Fr( x )` (probes
55	/// t5_ku_lhs / t5_up_inout). Returns the canonical name and multiplicity.
56	fn canon_builtin(name: &str) -> Option<(&'static str, bool)> {
57	    match name.to_ascii_lowercase().as_str() {
58	        "k" => Some(("K", false)),
59	        "ku" => Some(("KU", true)),
60	        "kd" => Some(("KD", true)),
61	        "in" => Some(("In", false)),
62	        "out" => Some(("Out", false)),
63	        "fr" => Some(("Fr", false)),
64	        _ => None,
65	    }
66	}
67	
68	/// The fact with its name/multiplicity rewritten to the canonical builtin
69	/// form when it matches one (otherwise unchanged).
70	fn canon_fact(f: &Fact) -> Fact {
71	    match canon_builtin(&f.name) {
72	        Some((name, persistent)) => Fact {
73	            persistent,
74	            name: name.to_string(),
75	            args: f.args.clone(),
76	            annotations: f.annotations.clone(),
77	        },
78	        None => f.clone(),
79	    }
80	}
