541	/// Collect action-fact uses from a lemma formula (label "Lemma"), tracking the
542	/// quantifier binder stack for the de Bruijn rendering of the fact terms.
543	fn gather_formula_facts(
544	    f: &Formula,
545	    stack: &mut Vec<Binder>,
546	    owner: &str,
547	    out: &mut Vec<(String, FactUse)>,
548	) {
549	    match f {
550	        Formula::False | Formula::True => {}
551	        Formula::Atom(Atom::Action(fact, _)) => {
552	            out.push((
553	                fact.name.clone(),
554	                FactUse {
555	                    label: "Lemma",
556	                    owner: owner.to_string(),
557	                    arity: fact.args.len(),
558	                    persistent: fact.persistent,
559	                    render: show_haskell_fact(fact, stack),
560	                },
561	            ));
562	        }
563	        Formula::Atom(_) => {}
564	        Formula::Not(g) => gather_formula_facts(g, stack, owner, out),
565	        Formula::And(a, b)
566	        | Formula::Or(a, b)
567	        | Formula::Implies(a, b)
568	        | Formula::Iff(a, b) => {
569	            gather_formula_facts(a, stack, owner, out);
570	            gather_formula_facts(b, stack, owner, out);
571	        }
572	        Formula::Forall(vs, g) | Formula::Exists(vs, g) => {
573	            let n = vs.len();
574	            for v in vs {
575	                stack.push((v.name.clone(), v.idx, var_class(v)));
576	            }
577	            gather_formula_facts(g, stack, owner, out);
578	            for _ in 0..n {
579	                stack.pop();
580	            }
581	        }
582	    }
583	}
