632	fn render_fact_blocks(conflicts: &[(String, Vec<String>)], intro1: &str, intro2: &str) -> String {
633	    // conflicts: (lowercased fact name, item lines) already ordered.
634	    let mut body = format!("{}\n{}\n  ", intro1, intro2);
635	    for (i, (lname, items)) in conflicts.iter().enumerate() {
636	        let block = format!("  Fact `{}':\n\n{}\n  ", lname, items.join("\n    \n"));
637	        if i == 0 {
638	            body.push_str("\n\n");
639	        } else {
640	            body.push('\n');
641	        }
642	        body.push_str(&block);
643	    }
644	    body
645	}
