720	pub fn fact_arity(thy: &Theory) -> Vec<WfError> {
721	    let uses = gather_fact_uses(thy);
722	    let mut conflicts: Vec<(String, Vec<String>)> = Vec::new();
723	    for (name, us) in &uses {
724	        let arities: std::collections::BTreeSet<usize> = us.iter().map(|u| u.arity).collect();
725	        if arities.len() < 2 {
726	            continue;
727	        }
728	        // One item per distinct (label, owner, arity, render): two uses in
729	        // the same owner at the same arity are BOTH listed when their raw
730	        // renders differ (probe t5_lemdup: `Bound 3,2,1` and `Bound 4,3,2`).
731	        let mut seen: Vec<(&str, String, usize, String)> = Vec::new();
732	        let mut items: Vec<String> = Vec::new();
733	        for u in us {
734	            let k = (u.label, u.owner.clone(), u.arity, u.render.clone());
735	            if seen.contains(&k) {
736	                continue;
737	            }
738	            seen.push(k);
739	            let n = items.len() + 1;
740	            items.push(format!(
741	                "    {}. {} `{}', arity {}\n         {}",
742	                n, u.label, u.owner, u.arity, u.render
743	            ));
744	        }
745	        conflicts.push((name.to_lowercase(), items));
746	    }
747	    if conflicts.is_empty() {
748	        return vec![];
749	    }
750	    conflicts.sort_by(|a, b| a.0.cmp(&b.0));
751	    let msg = render_fact_blocks(
752	        &conflicts,
753	        "Same fact is used with different arities, i.e., Fact('A','B') is different from Fact('A'). ",
754	        "Check the arguments of your facts.",
755	    );
756	    vec![WfError::new(T_ARITY, msg)]
757	}
