823	pub fn fact_lhs_occur_no_rhs(thy: &Theory) -> Vec<WfError> {
824	    // The builtin facts KU/KD/In/Out/Fr (matched via normalization) do not
825	    // participate; the reserved proto-fact `K` DOES - a K-only premise is
826	    // listed (issue527 target: `factName `K'` with suggestion `F`).
827	    let excluded = |name: &str| matches!(canon_builtin(name), Some((c, _)) if c != "K");
828	    let mut lhs: Vec<FactId> = Vec::new();
829	    let mut rhs: Vec<FactId> = Vec::new();
830	    for r in protocol_rules(thy) {
831	        for f in &r.premises {
832	            if excluded(&f.name) {
833	                continue;
834	            }
835	            lhs.push(FactId {
836	                name: f.name.clone(),
837	                arity: f.args.len(),
838	                persistent: f.persistent,
839	                rule: r.name.clone(),
840	            });
841	        }
842	        for f in &r.conclusions {
843	            if excluded(&f.name) {
844	                continue;
845	            }
846	            rhs.push(FactId {
847	                name: f.name.clone(),
848	                arity: f.args.len(),
849	                persistent: f.persistent,
850	                rule: r.name.clone(),
851	            });
852	        }
853	    }
854	    let rhs_idents: std::collections::HashSet<(String, usize, bool)> =
855	        rhs.iter().map(|f| f.ident()).collect();
856	
857	    // Every LHS occurrence whose fact identity (name, arity, multiplicity) is
858	    // absent from every RHS is listed, in source order, WITHOUT deduplication:
859	    // one entry per premise occurrence, so a fact repeated in a single rule and
860	    // the same fact reused across several rules each contribute their own entry
861	    // (probes lhs1/lhs2/lhs3).
862	    let mut entries: Vec<String> = Vec::new();
863	    for f in &lhs {
864	        if rhs_idents.contains(&f.ident()) {
865	            continue;
866	        }
867	        let mut line = f.render();
868	        if let Some(sugg) = nearest_rhs(&f.name, &rhs) {
869	            line.push_str(&format!(". Perhaps you want to use the fact {}", sugg.render()));
870	        }
871	        entries.push(line);
872	    }
873	    if entries.is_empty() {
874	        return vec![];
875	    }
876	    // Item numbers are right-aligned to the widest index with a two-space
877	    // margin ("   1." ... "  10." - probe t5_align / ble & mesh targets).
878	    let w = entries.len().to_string().len();
879	    let items: Vec<String> = entries
880	        .iter()
881	        .enumerate()
882	        .map(|(i, e)| format!("  {:>w$}. {}", i + 1, e, w = w))
883	        .collect();
884	    vec![WfError::new(T_LHSRHS, items.join("\n  \n"))]
885	}
886	
887	/// Nearest RHS fact by name edit distance, if within threshold (<= 3).
888	fn nearest_rhs<'a>(name: &str, rhs: &'a [FactId]) -> Option<&'a FactId> {
889	    let mut best: Option<(usize, &FactId)> = None;
890	    for f in rhs {
891	        let d = edit_distance(name, &f.name);
892	        match best {
893	            Some((bd, _)) if d >= bd => {}
894	            _ => best = Some((d, f)),
895	        }
896	    }
897	    match best {
898	        Some((d, f)) if d <= 3 => Some(f),
899	        _ => None,
900	    }
901	}
902	
903	fn edit_distance(a: &str, b: &str) -> usize {
904	    let a: Vec<char> = a.chars().collect();
905	    let b: Vec<char> = b.chars().collect();
906	    let mut prev: Vec<usize> = (0..=b.len()).collect();
907	    let mut cur = vec![0usize; b.len() + 1];
908	    for i in 1..=a.len() {
909	        cur[0] = i;
910	        for j in 1..=b.len() {
911	            let cost = if a[i - 1] == b[j - 1] { 0 } else { 1 };
912	            cur[j] = (prev[j] + 1).min(cur[j - 1] + 1).min(prev[j - 1] + cost);
913	        }
914	        std::mem::swap(&mut prev, &mut cur);
915	    }
916	    prev[b.len()]
917	}
