996	// ---------------------------------------------------------------------------
997	// Formula-variable sorts and sort-aware binding
998	// ---------------------------------------------------------------------------
999	// Formula quantifiers bind sorted variables. The oracle treats a bound variable
1000	// and a use as the same variable only when they share a name AND a sort class,
1001	// so a temporal binder `#x` does NOT bind a message-position use `x`. The parser
1002	// tags an un-annotated message-position variable as `Untagged` and an annotated
1003	// one as `Msg`; the oracle treats those as one variable, so both collapse to the
1004	// `Msg` class here (this is what keeps a quantified message variable bound to its
1005	// uses across the parser's tag differences).
1006	
1007	/// Sort equivalence class of a formula variable, used for binding and guarding.
1008	#[derive(Clone, Copy, PartialEq, Eq, Hash)]
1009	enum SortClass {
1010	    Msg,
1011	    Pub,
1012	    Fresh,
1013	    Node,
1014	    Nat,
1015	}
1016	
1017	fn sort_class(s: SortHint) -> SortClass {
1018	    match s {
1019	        SortHint::Msg | SortHint::Untagged | SortHint::Suffix(SuffixSort::Msg) => SortClass::Msg,
1020	        SortHint::Pub | SortHint::Suffix(SuffixSort::Pub) => SortClass::Pub,
1021	        SortHint::Fresh | SortHint::Suffix(SuffixSort::Fresh) => SortClass::Fresh,
1022	        SortHint::Node | SortHint::Suffix(SuffixSort::Node) => SortClass::Node,
1023	        SortHint::Nat | SortHint::Suffix(SuffixSort::Nat) => SortClass::Nat,
1024	    }
1025	}
1026	
1027	fn var_class(v: &VarSpec) -> SortClass {
1028	    sort_class(v.sort)
1029	}
1030	
1031	/// A binder on the quantifier stack: the bound variable's name, numeric index
1032	/// and sort class. The index participates in variable identity (probe g5_idx:
1033	/// a binder `y` does not bind a use `y.1`).
1034	type Binder = (String, u64, SortClass);
1035	
1036	/// The identity key of a formula variable: name, index and sort class.
1037	fn formula_var_key(v: &VarSpec) -> (String, u64, SortClass) {
1038	    (v.name.clone(), v.idx, var_class(v))
1039	}
1040	
1041	// ---------------------------------------------------------------------------
1042	// Quantifier sorts (variables quantified over a disallowed sort)
1043	// ---------------------------------------------------------------------------
1044	// Quantifying over a public or fresh variable is rejected; message, temporal
1045	// (node) and natural-number quantifiers are allowed. Each offending variable is
1046	// reported as a Haskell `(name, LSort)` tuple, collected in binding order.
1047	
1048	fn wrong_lsort(s: SortHint) -> Option<&'static str> {
1049	    match sort_class(s) {
1050	        SortClass::Pub => Some("LSortPub"),
1051	        SortClass::Fresh => Some("LSortFresh"),
1052	        SortClass::Msg | SortClass::Node | SortClass::Nat => None,
1053	    }
1054	}
1055	
1056	/// Collect `(name,LSort)` tokens for every quantified variable of a disallowed
1057	/// sort, visiting outer binders before inner ones (binding order).
1058	fn wrong_quant_sorts(f: &Formula, out: &mut Vec<String>) {
1059	    match f {
1060	        Formula::Forall(vs, g) | Formula::Exists(vs, g) => {
1061	            for v in vs {
1062	                if let Some(ls) = wrong_lsort(v.sort) {
1063	                    out.push(format!("(\"{}\",{})", v.name, ls));
1064	                }
1065	            }
1066	            wrong_quant_sorts(g, out);
1067	        }
1068	        Formula::Not(g) => wrong_quant_sorts(g, out),
1069	        Formula::And(a, b)
1070	        | Formula::Or(a, b)
1071	        | Formula::Implies(a, b)
1072	        | Formula::Iff(a, b) => {
1073	            wrong_quant_sorts(a, out);
1074	            wrong_quant_sorts(b, out);
1075	        }
1076	        _ => {}
1077	    }
1078	}
