1080	fn quantifier_sorts_entry(entity: &str, name: &str, f: &Formula) -> Option<String> {
1081	    let mut tokens = Vec::new();
1082	    wrong_quant_sorts(f, &mut tokens);
1083	    if tokens.is_empty() {
1084	        return None;
1085	    }
1086	    let prefix = format!("  {} `{}' uses quantifiers with wrong sort:", entity, name);
1087	    Some(fill_after_prefix(&prefix, &tokens, 4, FILL_WIDTH))
