1090	// ---------------------------------------------------------------------------
1091	// Formula terms (ill-formed terms in lemma / restriction formulas)
1092	// ---------------------------------------------------------------------------
1093	// A lemma/restriction formula may only use terms built from public constants
1094	// and BOUND node/message variables via non-reducible function symbols. A term
1095	// is reported "of the wrong form" if it contains a FREE variable or a REDUCIBLE
1096	// function symbol. The whole offending top-level term (each argument of each
1097	// atom) is reported, rendered in the oracle's raw term representation:
1098	//   - a bound variable  -> `Bound N` (de Bruijn: 0 = innermost binder)
1099	//   - a free  variable  -> `Free <pp_var>`  (keeps the sort prefix)
1100	//   - a function app    -> `f(a,b)`  (args comma-joined, NO space)
1101	//   - a tuple           -> `pair(a,pair(b,c))` (right-nested binary pairs)
1102	//   - a public constant -> `'name'`
1103	// The set of reducible function symbol names is caller-supplied (the caller
1104	// computes reducibility from the equation theory / Maude); this module only
1105	// consumes it. `formula_terms` is the zero-reducible-symbols convenience
1106	// wrapper (free variables only). See BEHAVIOR.md.
1107	
1108	const FORMULA_TERMS_HELP: &str = "  The only allowed terms are public constants and bound node and\n  message variables. If you encounter free message variables, then\n  you might have forgotten a #-prefix. Sort prefixes can only be\n  dropped where this is unambiguous. Moreover, reducible function\n  symbols are disallowed.";
1109	
1110	/// De Bruijn index of `(name, idx, class)` on the binder stack (outermost
1111	/// pushed first): the innermost binder matching name, index AND class is 0.
1112	/// `None` if no binder matches (the variable is free). Every quantified
1113	/// variable - including temporals and sort-mismatched ones - occupies one
1114	/// stack slot, so the index counts all binders between the use and its
1115	/// matching binder.
1116	fn debruijn_index(stack: &[Binder], name: &str, idx: u64, class: SortClass) -> Option<usize> {
1117	    stack
1118	        .iter()
1119	        .rposition(|(n, i, c)| n == name && *i == idx && *c == class)
1120	        .map(|pos| stack.len() - 1 - pos)
1121	}
1122	
1123	/// Render a term in the oracle's raw "wrong form" representation.
1124	fn show_wf_term(t: &Term, stack: &[Binder]) -> String {
1125	    match t {
1126	        Term::Var(v) => match debruijn_index(stack, &v.name, v.idx, var_class(v)) {
1127	            Some(idx) => format!("Bound {}", idx),
1128	            None => format!("Free {}", pp_var(v)),
1129	        },
1130	        Term::PubLit(s) => format!("'{}'", s),
1131	        Term::FreshLit(s) => format!("~'{}'", s),
1132	        Term::NatLit(s) => format!("%'{}'", s),
1133	        Term::Number(n) => n.to_string(),
1134	        Term::NumberOne => "1".to_string(),
1135	        Term::NatOne => "%1".to_string(),
1136	        Term::DhNeutral => "DH_neutral".to_string(),
1137	        Term::App(name, args) => {
1138	            if args.is_empty() {
1139	                name.clone()
1140	            } else {
1141	                let parts: Vec<String> = args.iter().map(|a| show_wf_term(a, stack)).collect();
1142	                format!("{}({})", name, parts.join(","))
1143	            }
1144	        }
1145	        Term::AlgApp(name, a, b) => {
1146	            format!("{}({},{})", name, show_wf_term(a, stack), show_wf_term(b, stack))
1147	        }
1148	        Term::Pair(items) => show_wf_pair(items, stack),
1149	        Term::Diff(a, b) => {
1150	            format!("diff({},{})", show_wf_term(a, stack), show_wf_term(b, stack))
1151	        }
1152	        Term::BinOp(op, a, b) => {
1153	            let name = match op {
1154	                BinOp::Exp => "exp",
1155	                BinOp::Mult => "mult",
1156	                BinOp::Union => "union",
1157	                BinOp::Xor => "xor",
1158	                BinOp::NatPlus => "tadd",
1159	            };
1160	            format!("{}({},{})", name, show_wf_term(a, stack), show_wf_term(b, stack))
1161	        }
1162	        Term::PatMatch(inner) => show_wf_term(inner, stack),
1163	    }
1164	}
1165	
1166	/// Render a tuple as right-nested binary `pair(...)` applications.
1167	fn show_wf_pair(items: &[Term], stack: &[Binder]) -> String {
1168	    match items {
1169	        [] => "pair".to_string(),
1170	        [only] => show_wf_term(only, stack),
1171	        [head, rest @ ..] => {
1172	            format!("pair({},{})", show_wf_term(head, stack), show_wf_pair(rest, stack))
1173	        }
1174	    }
1175	}
