1177	/// True iff `t` contains a free variable or a reducible function symbol, i.e.
1178	/// the term is "of the wrong form" for a trace formula.
1179	fn term_is_ill_formed(
1180	    t: &Term,
1181	    stack: &[Binder],
1182	    reducible: &std::collections::BTreeSet<String>,
1183	) -> bool {
1184	    match t {
1185	        Term::Var(v) => debruijn_index(stack, &v.name, v.idx, var_class(v)).is_none(), // free -> ill
1186	        Term::PubLit(_)
1187	        | Term::FreshLit(_)
1188	        | Term::NatLit(_)
1189	        | Term::Number(_)
1190	        | Term::NumberOne
1191	        | Term::NatOne
1192	        | Term::DhNeutral => false,
1193	        Term::App(name, args) => {
1194	            reducible.contains(name) || args.iter().any(|a| term_is_ill_formed(a, stack, reducible))
1195	        }
1196	        Term::AlgApp(name, a, b) => {
1197	            reducible.contains(name)
1198	                || term_is_ill_formed(a, stack, reducible)
1199	                || term_is_ill_formed(b, stack, reducible)
1200	        }
1201	        Term::Pair(items) => items.iter().any(|a| term_is_ill_formed(a, stack, reducible)),
1202	        Term::Diff(a, b) | Term::BinOp(_, a, b) => {
1203	            term_is_ill_formed(a, stack, reducible) || term_is_ill_formed(b, stack, reducible)
1204	        }
1205	        Term::PatMatch(inner) => term_is_ill_formed(inner, stack, reducible),
1206	    }
1207	}
