1339	// ---------------------------------------------------------------------------
1340	// Formula guardedness (decision procedure over the guarded fragment)
1341	// ---------------------------------------------------------------------------
1342	// A LEMMA formula must be convertible to guarded form (an unguarded RESTRICTION
1343	// is a fatal error, not a warning, so this check is lemma-only). Directly
1344	// nested quantifiers of the same kind FUSE into one binder list before the
1345	// check (probes g5_e_nest / g5_a_nest; the report renders the fused form -
1346	// g5_a_nest_noimpl). A universal is guarded only as `guard ==> rest`; an
1347	// existential's guard region is its whole body. Within the guard region a
1348	// variable is guarded (resolved) by
1349	//   1. occurring anywhere inside an ACTION atom reachable through
1350	//      conjunctions (all action atoms are collected first - g5_e_actorder), or
1351	//   2. an EQUALITY atom reachable through conjunctions, processed in a SINGLE
1352	//      left-to-right pass (g5_e_eqchain vs g5_e_revchain): when one side of
1353	//      the equality contains no unresolved quantified variables, every
1354	//      unresolved quantified variable of the other side becomes resolved
1355	//      (g5_e_eqbare/g5_e_eqinner/g5_e_eqpair; side-based, not unification -
1356	//      g5_e_unif).
1357	// Disjunction, negation, implication, ordering/subterm/last atoms and nested
1358	// quantifiers contribute no guards. The first failing quantifier (antecedent
1359	// before consequent, left before right) is reported together with the whole
1360	// lemma formula.
1361	
1362	/// A guardedness failure and its reason.
1363	enum GuardFail {
1364	    /// A quantifier binds variables not guarded by an action atom.
1365	    Unguarded(Vec<VarSpec>),
1366	    /// A universal quantifier's body is not a top-level implication.
1367	    NoImplication,
1368	}
1369	
1370	/// Fuse directly nested quantifiers of the same kind (`∀x.∀y.φ` -> `∀x y.φ`),
1371	/// recursively over the whole formula. The guardedness decision AND the
1372	/// report's formula rendering both operate on the fused form.
1373	fn fuse_quantifiers(f: &Formula) -> Formula {
1374	    match f {
1375	        Formula::Forall(vs, g) => {
1376	            let mut vars = vs.clone();
1377	            let mut body = fuse_quantifiers(g);
1378	            while let Formula::Forall(vs2, g2) = body {

1379	                vars.extend(vs2);
1380	                body = *g2;
1381	            }
1382	            Formula::Forall(vars, Box::new(body))
1383	        }
1384	        Formula::Exists(vs, g) => {
1385	            let mut vars = vs.clone();
1386	            let mut body = fuse_quantifiers(g);
1387	            while let Formula::Exists(vs2, g2) = body {
1388	                vars.extend(vs2);
1389	                body = *g2;
1390	            }
1391	            Formula::Exists(vars, Box::new(body))
1392	        }
1393	        Formula::Not(g) => Formula::Not(Box::new(fuse_quantifiers(g))),
1394	        Formula::And(a, b) => Formula::And(
1395	            Box::new(fuse_quantifiers(a)),
1396	            Box::new(fuse_quantifiers(b)),
1397	        ),
1398	        Formula::Or(a, b) => Formula::Or(
1399	            Box::new(fuse_quantifiers(a)),
1400	            Box::new(fuse_quantifiers(b)),
1401	        ),
1402	        Formula::Implies(a, b) => Formula::Implies(
1403	            Box::new(fuse_quantifiers(a)),
1404	            Box::new(fuse_quantifiers(b)),
1405	        ),
1406	        Formula::Iff(a, b) => Formula::Iff(
1407	            Box::new(fuse_quantifiers(a)),
1408	            Box::new(fuse_quantifiers(b)),
1409	        ),
1410	        other => other.clone(),
1411	    }
1412	}
1413	
1414	/// Collect the variables of every ACTION atom reachable through conjunctions of
1415	/// `f`. These are the variables a guard binds outright.
1416	fn collect_guard_vars(f: &Formula, out: &mut Vec<VarSpec>) {
1417	    match f {
1418	        Formula::Atom(Atom::Action(fact, t)) => {
1419	            collect_fact_vars(fact, out);
1420	            collect_term_vars(t, out);
1421	        }
1422	        Formula::And(a, b) => {
1423	            collect_guard_vars(a, out);
1424	            collect_guard_vars(b, out);
1425	        }
1426	        _ => {}
1427	    }
1428	}
1429	
1430	/// Collect the EQUALITY atoms reachable through conjunctions of `f`, in
1431	/// left-to-right source order.
1432	fn collect_guard_eqs<'a>(f: &'a Formula, out: &mut Vec<(&'a Term, &'a Term)>) {
1433	    match f {
1434	        Formula::Atom(Atom::Eq(l, r)) => out.push((l, r)),
1435	        Formula::And(a, b) => {
1436	            collect_guard_eqs(a, out);
1437	            collect_guard_eqs(b, out);
1438	        }
1439	        _ => {}
1440	    }
1441	}
1442	
1443	type VKey = (String, u64, SortClass);
1444	
1445	/// The subset of `current` (the quantifier's own variables) resolved by the
1446	/// guard region `f`: first every conjunction-reachable action atom resolves
1447	/// all of its variables, then the conjunction-reachable equalities are
1448	/// processed once, left to right - an equality whose one side is clean (has no
1449	/// unresolved current variables) resolves the current variables of its other
1450	/// side.
1451	fn resolved_guard_keys(
1452	    f: &Formula,
1453	    current: &std::collections::HashSet<VKey>,
1454	) -> std::collections::HashSet<VKey> {
1455	    let mut resolved: std::collections::HashSet<VKey> = std::collections::HashSet::new();
1456	    let mut avs = Vec::new();
1457	    collect_guard_vars(f, &mut avs);
1458	    for v in &avs {
1459	        let k = formula_var_key(v);
1460	        if current.contains(&k) {
1461	            resolved.insert(k);
1462	        }
1463	    }
1464	    let mut eqs = Vec::new();
1465	    collect_guard_eqs(f, &mut eqs);
1466	    for (l, r) in eqs {
1467	        let unresolved_side = |t: &Term| -> Vec<VKey> {
1468	            let mut vs = Vec::new();
1469	            collect_term_vars(t, &mut vs);
1470	            vs.iter()
1471	                .map(formula_var_key)
1472	                .filter(|k| current.contains(k) && !resolved.contains(k))
1473	                .collect()
1474	        };
1475	        let lu = unresolved_side(l);
1476	        let ru = unresolved_side(r);
1477	        if lu.is_empty() && !ru.is_empty() {
1478	            resolved.extend(ru);
1479	        } else if ru.is_empty() && !lu.is_empty() {
1480	            resolved.extend(lu);
1481	        }
1482	    }
1483	    resolved
1484	}
1485	
1486	/// Quantified variables of `vs` not resolved by the guard region `region`, in
1487	/// binding order.
1488	fn unguarded_vars(vs: &[VarSpec], region: &Formula) -> Vec<VarSpec> {
1489	    let current: std::collections::HashSet<VKey> = vs.iter().map(formula_var_key).collect();
1490	    let resolved = resolved_guard_keys(region, &current);
1491	    vs.iter()
1492	        .filter(|v| !resolved.contains(&formula_var_key(v)))
1493	        .cloned()
1494	        .collect()
1495	}
1496	
1497	/// Return the first guardedness failure and the failing quantifier subformula.
1498	/// Expects a quantifier-fused formula (see [`fuse_quantifiers`]).
1499	fn find_guard_failure(f: &Formula) -> Option<(GuardFail, Formula)> {
1500	    match f {
1501	        Formula::Forall(vs, body) => match &**body {
1502	            Formula::Implies(guard, rest) => {
1503	                let unguarded = unguarded_vars(vs, guard);
1504	                if !unguarded.is_empty() {
1505	                    return Some((GuardFail::Unguarded(unguarded), f.clone()));
1506	                }
1507	                find_guard_failure(guard).or_else(|| find_guard_failure(rest))
1508	            }
1509	            _ => Some((GuardFail::NoImplication, f.clone())),
1510	        },
1511	        Formula::Exists(vs, body) => {
1512	            let unguarded = unguarded_vars(vs, body);
1513	            if !unguarded.is_empty() {
1514	                return Some((GuardFail::Unguarded(unguarded), f.clone()));
1515	            }
1516	            find_guard_failure(body)
1517	        }
1518	        Formula::Not(g) => find_guard_failure(g),
1519	        Formula::And(a, b)
1520	        | Formula::Or(a, b)
1521	        | Formula::Implies(a, b)
1522	        | Formula::Iff(a, b) => find_guard_failure(a).or_else(|| find_guard_failure(b)),
1523	        _ => None,
1524	    }
1525	}
1526	
1527	/// The guardedness report entry for one lemma, or `None` when it is guarded.
1528	fn guardedness_entry(name: &str, f: &Formula) -> Option<String> {
1529	    let f = &fuse_quantifiers(f);
1530	    let (fail, sub) = find_guard_failure(f)?;
1531	    let reason = match fail {
1532	        GuardFail::Unguarded(vars) => {
1533	            let vs: Vec<String> = vars.iter().map(|v| format!("'{}'", pp_var(v))).collect();
1534	            format!("unguarded variable(s) {} in the subformula", vs.join(", "))
1535	        }
1536	        GuardFail::NoImplication => {
1537	            "universal quantifier without toplevel implication".to_string()
1538	        }
1539	    };
1540	    // The formula is embedded as `      "..."`: its first character sits at
1541	    // column 7 (after six spaces and the quote).
1542	    let pp_sub = crate::formula::pp_formula_wrapped(&sub, 7);
1543	    let pp_whole = crate::formula::pp_formula_wrapped(f, 7);
1544	    Some(format!(
1545	        "  Lemma `{}' cannot be converted to a guarded formula:\n    {}\n      \"{}\"\n    in the formula\n      \"{}\"",
1546	        name, reason, pp_sub, pp_whole
1547	    ))
1548	}
