1550	/// Standalone guardedness check over every lemma, merged into one topic block.
1551	pub fn formula_guardedness(thy: &Theory) -> Vec<WfError> {
1552	    let mut entries: Vec<String> = Vec::new();
1553	    for it in &thy.items {
1554	        if let TheoryItem::Lemma(l) = it {
1555	            if let Some(e) = guardedness_entry(&l.name, &l.formula) {
1556	                entries.push(e);
1557	            }
1558	        }
1559	    }
1560	    if entries.is_empty() {
1561	        vec![]
