1567	// ---------------------------------------------------------------------------
1568	// Formula-check bundle (Quantifier sorts, Formula terms, Formula guardedness)
1569	// ---------------------------------------------------------------------------
1570	// The three per-formula checks are run together, item by item, in the oracle's
1571	// checking order: every lemma (source order) first, then every restriction
1572	// (source order). For each item the three topics are emitted in the order
1573	// Quantifier sorts, Formula terms, Formula guardedness (guardedness for lemmas
1574	// only). Consecutive entries sharing a topic merge under a single header; a
1575	// topic that recurs after an intervening different topic starts a fresh block
1576	// (observed: L1=QS, L2=FT, L3=QS renders as three blocks).
1577	
1578	/// The formula-bearing items in checking order: (entity, name, formula,
1579	/// is_lemma). Lemmas come before restrictions regardless of source order.
1580	fn formula_items(thy: &Theory) -> Vec<(&'static str, &str, &Formula, bool)> {
1581	    let mut out: Vec<(&'static str, &str, &Formula, bool)> = Vec::new();
1582	    for it in &thy.items {
1583	        if let TheoryItem::Lemma(l) = it {
1584	            out.push(("Lemma", l.name.as_str(), &l.formula, true));
1585	        }
1586	    }
1587	    for it in &thy.items {
1588	        if let TheoryItem::Restriction(r) | TheoryItem::LegacyAxiom(r) = it {
1589	            out.push(("Restriction", r.name.as_str(), &r.formula, false));
1590	        }
1591	    }
1592	    out
1593	}
1594	
1595	/// Merge a sequence of `(topic, entry)` pairs, joining only CONSECUTIVE
1596	/// same-topic entries (separator `"\n  \n"`) into one `WfError` block.
1597	fn merge_consecutive(seq: Vec<(&'static str, String)>) -> Vec<WfError> {
1598	    let mut out: Vec<WfError> = Vec::new();
1599	    for (topic, entry) in seq {
1600	        if let Some(last) = out.last_mut() {
1601	            if last.topic == topic {
1602	                last.message.push_str("\n  \n");
1603	                last.message.push_str(&entry);
1604	                continue;
1605	            }
1606	        }
1607	        out.push(WfError::new(topic, entry));
1608	    }
1609	    out
1610	}
