1612	/// Run the Quantifier-sorts / Formula-terms / Formula-guardedness bundle over
1613	/// all lemmas and restrictions, producing the merged topic blocks in report
1614	/// order.
1615	pub fn formula_reports(
1616	    thy: &Theory,
1617	    reducible: &std::collections::BTreeSet<String>,
1618	) -> Vec<WfError> {
1619	    let mut seq: Vec<(&'static str, String)> = Vec::new();
1620	    for (entity, name, formula, is_lemma) in formula_items(thy) {
1621	        if let Some(e) = quantifier_sorts_entry(entity, name, formula) {
1622	            seq.push((T_QUANT_SORTS, e));
1623	        }
1624	        let terms = ill_terms(formula, reducible);
1625	        if !terms.is_empty() {
1626	            seq.push((T_FORMULA_TERMS, formula_terms_entry(entity, name, &terms)));
1627	        }
1628	        if is_lemma {
1629	            if let Some(e) = guardedness_entry(name, formula) {
1630	                seq.push((T_GUARD, e));
1631	            }
1632	        }
1633	    }
1634	    merge_consecutive(seq)
1635	}
