1659	fn collect_nat_issues(t: &Term, out: &mut Vec<String>) {
1660	    if let Term::BinOp(BinOp::NatPlus, _, _) = t {
1661	        let term_pp = pp_term(t);
1662	        let mut vs = Vec::new();
1663	        collect_term_vars(t, &mut vs);
1664	        for v in vs {
1665	            if v.sort != SortHint::Nat {
1666	                let entry = format!("  {} in term {} must be of sort nat", pp_var(&v), term_pp);
1667	                if !out.contains(&entry) {
1668	                    out.push(entry);
1669	                }
1670	            }
1671	        }
1672	    }
1673	    // recurse
1674	    match t {
1675	        Term::App(_, args) | Term::Pair(args) => {
1676	            for a in args {
1677	                collect_nat_issues(a, out);
1678	            }
1679	        }
1680	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
1681	            collect_nat_issues(a, out);
1682	            collect_nat_issues(b, out);
1683	        }
1684	        Term::PatMatch(inner) => collect_nat_issues(inner, out),
1685	        _ => {}
1686	    }
1687	}
