1690	// 13. Subterm Convergence Warning
1691	// ---------------------------------------------------------------------------
1692	
1693	pub fn subterm_convergence(thy: &Theory) -> Vec<WfError> {
1694	    // An equation is subterm convergent when its RHS is a subterm of its LHS
1695	    // or GROUND (no variables - probes t5_sub_ground/t5_sub_groundapp). The
1696	    // flagged equations are listed sorted by their rendered form, not source
1697	    // order (t5_sub_order*; mesh: k1..k4 before s1), and wide equations wrap
1698	    // via the equation layout engine (ble f6 / mesh k2).
1699	    let mut bad: Vec<(String, String)> = Vec::new(); // (flat sort key, rendered)
1700	    for it in &thy.items {
1701	        if let TheoryItem::Equations { convergent, eqs } = it {
1702	            if *convergent {
1703	                continue; // user asserted convergence
1704	            }
1705	            for eq in eqs {
1706	                if !is_subterm(&eq.rhs, &eq.lhs) && term_has_vars(&eq.rhs) {
1707	                    let key = format!("{} = {}", pp_term(&eq.lhs), pp_term(&eq.rhs));
1708	                    bad.push((key, crate::pretty::pp_equation(&eq.lhs, &eq.rhs)));
1709	                }
1710	            }
1711	        }
1712	    }
1713	    if bad.is_empty() {
1714	        return vec![];
1715	    }
1716	    bad.sort();
1717	    let bad: Vec<String> = bad.into_iter().map(|(_, r)| r).collect();
1718	    let intro = "  User-defined equations must be convergent and have the finite variant property. The following equations are not subterm convergent. If you are sure that the set of equations is nevertheless convergent and has the finite variant property, you can ignore this warning and continue ";
1719	    let manual = " For more information, please refer to the manual : https://tamarin-prover.com/manual/master/book/010_modeling-issues.html ";
1720	    let msg = format!("{}\n\n{}\n   \n{}", intro, bad.join("\n"), manual);
1721	    vec![WfError::new(T_SUBTERM, msg)]
1722	}
