1724	/// Does the term contain any variable? (A ground RHS is convergent.)
1725	fn term_has_vars(t: &Term) -> bool {
1726	    let mut vs = Vec::new();
1727	    collect_term_vars(t, &mut vs);
1728	    !vs.is_empty()
1729	}
