1731	/// Structural subterm test: does `small` occur as a subterm of `big`?
1732	fn is_subterm(small: &Term, big: &Term) -> bool {
1733	    if small == big {
1734	        return true;
1735	    }
1736	    match big {
1737	        Term::App(_, args) | Term::Pair(args) => args.iter().any(|a| is_subterm(small, a)),
1738	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
1739	            is_subterm(small, a) || is_subterm(small, b)
1740	        }
1741	        Term::PatMatch(inner) => is_subterm(small, inner),
1742	        _ => false,
1743	    }
1744	}
