1849	// ---------------------------------------------------------------------------
1850	// 11 & 12. Left rule / Right rule (diff mode only)
1851	// ---------------------------------------------------------------------------
1852	// A diff rule may carry explicit `left`/`right` projections. Each explicit
1853	// projection must equal the corresponding projection of the parent diff rule
1854	// (diff(a,b) -> a on the left, -> b on the right). When it differs, the rule is
1855	// "inconsistent". For a single rule the left projection is checked first and,
1856	// if inconsistent, the right is not reported (observed via probe diff_both).
1857	pub fn diff_left_right(thy: &Theory) -> Vec<WfError> {
1858	    if !thy.is_diff {
1859	        return vec![];
1860	    }
1861	    let mut left_entries: Vec<String> = Vec::new();
1862	    let mut right_entries: Vec<String> = Vec::new();
1863	    for r in protocol_rules(thy) {
1864	        if let Some((left, right)) = &r.left_right {
1865	            if !rule_matches_projection(r, left, true) {
1866	                left_entries.push(inconsistent_entry("left", left, r));
1867	            } else if !rule_matches_projection(r, right, false) {
1868	                right_entries.push(inconsistent_entry("right", right, r));
1869	            }
1870	        }
1871	    }
1872	    let mut out = Vec::new();
1873	    if !left_entries.is_empty() {
1874	        out.push(WfError::new(T_LEFT, left_entries.join("\n  \n")));
1875	    }
1876	    if !right_entries.is_empty() {
1877	        out.push(WfError::new(T_RIGHT, right_entries.join("\n  \n")));
1878	    }
1879	    out
1880	}
1881	
1882	fn inconsistent_entry(side: &str, explicit: &Rule, parent: &Rule) -> String {
1883	    format!(
1884	        "  Inconsistent {} rule\n{}\n  \n  w.r.t.\n  \n{}",
1885	        side,
1886	        indent_block(&pp_rule(explicit), 4),
1887	        indent_block(&pp_rule(parent), 4)
1888	    )
1889	}
1890	
1891	/// True iff the explicit rule's fact lists equal the parent rule's projection.
1892	fn rule_matches_projection(parent: &Rule, explicit: &Rule, left: bool) -> bool {
1893	    facts_pp(&project_facts(&parent.premises, left)) == facts_pp(&explicit.premises)
1894	        && facts_pp(&project_facts(&parent.actions, left)) == facts_pp(&explicit.actions)
1895	        && facts_pp(&project_facts(&parent.conclusions, left)) == facts_pp(&explicit.conclusions)
1896	}
1897	
1898	fn facts_pp(fs: &[Fact]) -> String {
1899	    fs.iter().map(pp_fact).collect::<Vec<_>>().join(", ")
1900	}
1901	
1902	fn project_facts(fs: &[Fact], left: bool) -> Vec<Fact> {
1903	    fs.iter().map(|f| project_fact(f, left)).collect()
1904	}
1905	
1906	fn project_fact(f: &Fact, left: bool) -> Fact {
1907	    Fact {
1908	        persistent: f.persistent,
1909	        name: f.name.clone(),
1910	        args: f.args.iter().map(|a| project_term(a, left)).collect(),
1911	        annotations: f.annotations.clone(),
1912	    }
1913	}
1914	
1915	/// Project a diff term to one side: `diff(a, b)` becomes `a` (left) or `b`
1916	/// (right); all other terms are structurally mapped.
1917	fn project_term(t: &Term, left: bool) -> Term {
1918	    match t {
1919	        Term::Diff(a, b) => project_term(if left { a } else { b }, left),
1920	        Term::App(name, args) => {
1921	            Term::App(name.clone(), args.iter().map(|a| project_term(a, left)).collect())
1922	        }
1923	        Term::Pair(args) => Term::Pair(args.iter().map(|a| project_term(a, left)).collect()),
1924	        Term::AlgApp(name, a, b) => Term::AlgApp(
1925	            name.clone(),
1926	            Box::new(project_term(a, left)),
1927	            Box::new(project_term(b, left)),
1928	        ),
1929	        Term::BinOp(op, a, b) => Term::BinOp(
1930	            *op,
1931	            Box::new(project_term(a, left)),
1932	            Box::new(project_term(b, left)),
1933	        ),
1934	        Term::PatMatch(inner) => Term::PatMatch(Box::new(project_term(inner, left))),
1935	        other => other.clone(),
1936	    }
1937	}
