13	fn var(name: &str, sort: SortHint) -> VarSpec {
14	    VarSpec { name: name.into(), idx: 0, sort, typ: None }
15	}
16	fn mv(name: &str) -> Term { Term::Var(var(name, SortHint::Msg)) }
17	fn pl(name: &str) -> Term { Term::PubLit(name.into()) }
18	
19	fn fact(name: &str, args: Vec<Term>) -> Fact {
20	    Fact { persistent: false, name: name.into(), args, annotations: vec![] }
21	}
22	
23	fn rule(name: &str, prem: Vec<Fact>, act: Vec<Fact>, concl: Vec<Fact>) -> TheoryItem {
24	    TheoryItem::Rule(Rule {
25	        name: name.into(),
26	        modulo: None,
27	        attributes: vec![],
28	        let_block: vec![],
29	        premises: prem,
30	        actions: act,
31	        conclusions: concl,
32	        embedded_restrictions: vec![],
33	        variants: vec![],
34	        left_right: None,
35	    })
36	}
37	
38	fn theory(name: &str, items: Vec<TheoryItem>) -> Theory {
39	    Theory { is_diff: false, name: name.into(), configuration: None, items }
40	}
